"use strict";const newsContainer=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(response=>{response.json().then(json=>{json.forEach(element=>{var newsPost=document.createElement("li"),newsLink=document.createElement("a");newsLink.href=`/news/${element.id}`,newsLink.innerText=element.title,newsPost.appendChild(newsLink),newsContainer.appendChild(newsPost)})})});